/**
 * @param {number[]} digitSum
 * @return {number}
 */
function solve(digitSum) {
    const MOD = 1000000007n;
    const MAX_VALUE = 5000;
    const MAX_SUM = 50;

    // Step 1: Precompute all numbers <= 5000 and their digit sums.
    // Store them grouped by digit sum.
    const numbersByDigitSum = new Map();
    for (let i = 0; i <= MAX_VALUE; i++) {
        let sum = 0;
        let temp = i;
        while (temp > 0) {
            sum += temp % 10;
            temp = Math.floor(temp / 10);
        }
        if (!numbersByDigitSum.has(sum)) {
            numbersByDigitSum.set(sum, []);
        }
        numbersByDigitSum.get(sum).push(i);
    }

    // Sort the lists of numbers for each digit sum in ascending order.
    for (const [sum, nums] of numbersByDigitSum.entries()) {
        nums.sort((a, b) => a - b);
    }

    // Step 2: Dynamic Programming
    const n = digitSum.length;

    // DP state: dp[i][last_val] is the number of valid arrays of length i+1
    // whose last element is 'last_val'.
    // Since last_val can be up to 5000, we need a more constrained DP state.

    // Let's rephrase the DP based on the required digit sum at each step.

    // dp[i][j] = number of valid prefixes of length i+1 such that the i-th element (digitSum[i]) 
    // is the j-th smallest number that has digit sum = digitSum[i].
    // This is still too complex because the transition depends on the actual value of the (i-1)-th element.

    // A better DP state:
    // dp[i][last_val] = number of ways to form a valid prefix of length i+1 such that arr[i] = last_val.
    // Since MAX_VALUE is 5000, this is manageable (1000 * 5001 states).

    // Map to store the count for the current element's required digit sum, indexed by the value.
    // dp_current: Map<number, bigint> where key is the value arr[i] and value is the count of ways to reach it.

    // Initialize DP for the first element (i=0)
    let dp_current = new Map();
    const target_sum_0 = digitSum[0];
    const candidates0 = numbersByDigitSum.get(target_sum_0) || [];

    for (const num of candidates0) {
        dp_current.set(num, 1n);
    }

    // Iterate from the second element (i=1) up to n-1
    for (let i = 1; i < n; i++) {
        const target_sum_i = digitSum[i];
        const candidates_i = numbersByDigitSum.get(target_sum_i) || [];

        let dp_next = new Map();

        // Iterate over all possible current values (arr[i] = next_val)
        for (const next_val of candidates_i) {
            let count = 0n;

            // Sum up counts from previous valid states (dp_current)
            // We need prev_val <= next_val
            for (const [prev_val, ways] of dp_current.entries()) {
                if (prev_val <= next_val) {
                    count = (count + ways) % MOD;
                }
            }

            if (count > 0n) {
                dp_next.set(next_val, count);
            }
        }

        dp_current = dp_next;

        if (dp_current.size === 0) {
            // No valid array can be formed up to this point
            return 0;
        }
    }

    // Step 3: Calculate the total result
    let total_count = 0n;
    for (const ways of dp_current.values()) {
        total_count = (total_count + ways) % MOD;
    }

    return Number(total_count);
}

