	const MAX_VALUE int = 5000
	const MAX_SUM int = 50

	// Step 1: Precompute all numbers <= 5000 and their digit sums.
	// Store them grouped by digit sum.
	numbersByDigitSum := make(map[int][]int)
	for i := 0; i <= MAX_VALUE; i++ {
		sum := 0
		temp := i
		for temp > 0 {
			sum += temp % 10
			temp /= 10
		}
		if _, exists := numbersByDigitSum[sum]; !exists {
			numbersByDigitSum[sum] = []int{}
		}
		numbersByDigitSum[sum] = append(numbersByDigitSum[sum], i)
	}

	// Sort the lists of numbers for each digit sum in ascending order.
	for sum := range numbersByDigitSum {
		// Standard library sort for []int
		// Since we are using a map, we can't rely on a fixed order for iteration, 
		// but sorting the list for each sum is necessary for the DP approach used in the reference.
		// However, the DP structure below handles arbitrary order for candidates_i, 
		// so sorting is technically not required for correctness if the inner loop iterates over all previous states,
		// but let's sort for consistency with the conceptual reference.
		temp := numbersByDigitSum[sum]
		for i := 0; i < len(temp); i++ {
			for j := i + 1; j < len(temp); j++ {
				if temp[i] > temp[j] {
					temp[i], temp[j] = temp[j], temp[i]
				}
			}
		}
	}

	// Step 2: Dynamic Programming
	n := len(digitSum)

	// dp_current: map[int]int64 where key is the value arr[i] and value is the count of ways to reach it.
	dpCurrent := make(map[int]int64)

	// Initialize DP for the first element (i=0)
	targetSum0 := int(digitSum[0])
	candidates0, exists0 := numbersByDigitSum[targetSum0]
	if !exists0 {
		return 0
	}

	for _, num := range candidates0 {
		dpCurrent[num] = 1
	}

	// Iterate from the second element (i=1) up to n-1
	for i := 1; i < n; i++ {
		targetSumI := int(digitSum[i])
		candidatesI, existsI := numbersByDigitSum[targetSumI]
		if !existsI {
			return 0
		}

		dpNext := make(map[int]int64)

		// Iterate over all possible current values (arr[i] = nextVal)
		for _, nextVal := range candidatesI {
			count := int64(0)

			// Sum up counts from previous valid states (dpCurrent)
			// We need prevVal <= nextVal
			for prevVal, ways := range dpCurrent {
				if prevVal <= nextVal {
					count = (count + ways) % MOD
				}
			}

			if count > 0 {
				dpNext[nextVal] = count
			}
		}

		dpCurrent = dpNext

		if len(dpCurrent) == 0 {
			// No valid array can be formed up to this point
			return 0
		}
	}

	// Step 3: Calculate the total result
	totalCount := int64(0)
	for _, ways := range dpCurrent {
		totalCount = (totalCount + ways) % MOD
	}

	return totalCount
}
